import React, { useEffect, useState } from 'react';
import BlogCard from '../components/BlogCard'; // adjust path if needed
import axios from 'axios';

const BlogPage = () => {
  const [blogs, setBlogs] = useState([]);

  // ✅ Fetch blogs from backend
  useEffect(() => {
    fetchBlogs();
  }, []);

  const fetchBlogs = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/blogs');
      setBlogs(response.data);
    } catch (error) {
      console.error('Failed to fetch blogs:', error);
    }
  };

  // ✅ Handle delete callback from BlogCard
  const handleDelete = (deletedId) => {
    setBlogs((prevBlogs) => prevBlogs.filter((blog) => blog.id !== deletedId));
  };

  return (
    <div className="p-6 flex flex-wrap justify-center gap-4">
      {blogs.length === 0 ? (
        <p className="text-gray-600 text-center">No blogs found.</p>
      ) : (
        blogs.map((blog) =>
          blog ? (
            <BlogCard key={blog.id} blog={blog} onDelete={handleDelete} />
          ) : null
        )
      )}
    </div>
  );
};

export default BlogPage;
